}

function ToolBlock({ tool, path, content }) {
  const [open, setOpen] = useState(false);
  return (
    <div
      style={{
        backgroundColor: p.code,
        borderRadius: 8,
        border: `1px solid ${p.border}`,
        marginBottom: 8,
        overflow: "hidden",
      }}
    >
      <button
        onClick={() => setOpen(!open)}
        style={{
          display: "flex",
          alignItems: "center",
          gap: 8,
          width: "100%",
          padding: "8px 12px",
          background: "none",
          border: "none",
          cursor: "pointer",
        }}
      >
        <span
          style={{ fontFamily: f.mono, fontSize: 11, color: p.blue }}
        >
          {tool}
        </span>
        <span
          style={{
            fontFamily: f.mono,
            fontSize: 11,
            color: p.textMuted,
            flex: 1,
            textAlign: "left",
          }}
        >
          {path}
        </span>
        <span
          style={{
            transform: open ? "rotate(90deg)" : "none",
            transition: "0.15s",
            color: p.textDim,
            fontSize: 12,
          }}
        >
          ▸
        </span>
      </button>
      {open && (
        <pre
          style={{
            margin: 0,
            padding: "8px 12px",
            borderTop: `1px solid ${p.border}`,
            fontFamily: f.mono,
            fontSize: 11,
            color: p.textMuted,
            lineHeight: 1.6,
            overflowX: "auto",
            whiteSpace: "pre-wrap",
          }}
        >
          {content}
        </pre>
      )}
    </div>
  );
}

