const [newSessionModal, setNewSessionModal] = useState(false);
const [newContainerModal, setNewContainerModal] = useState(false);
const [configContainer, setConfigContainer] = useState(null);
const [vsCodeContainer, setVsCodeContainer] = useState(null);
const [inputValue, setInputValue] = useState("");
const feedRef = useRef(null);

const session = SESSIONS.find((s) => s.id === activeSession);
const containerObj = configContainer
  ? CONTAINERS.find((c) => c.id === configContainer)
  : null;
const vsCodeObj = vsCodeContainer
  ? CONTAINERS.find((c) => c.id === vsCodeContainer)
  : null;

useEffect(() => {
  if (feedRef.current)
    feedRef.current.scrollTop = feedRef.current.scrollHeight;
}, [activeSession]);

const quickCommands =
  session?.type !== "claude"
    ? [
        "lisa-loop status",
        "lisa-loop approve",
        "git diff --stat",
        "cargo test",
      ]
    : [];

if (containerObj) {
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');
        @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.4; } }
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: ${p.border}; border-radius: 2px; }
        input::placeholder, select { color: ${p.textDim}; }
      `}</style>
      <ContainerConfigView
        container={containerObj}
        onBack={() => setConfigContainer(null)}
        onOpenIDE={() => setVsCodeContainer(containerObj.id)}
      />
      {vsCodeObj && (
        <VSCodeOverlay
          container={vsCodeObj}
          onClose={() => setVsCodeContainer(null)}
        />
      )}
    </>
  );
}

return (
  <div
    style={{
      display: "flex",
      height: "100vh",
      width: "100%",
      backgroundColor: p.bg,
      fontFamily: f.sans,
      position: "relative",
      overflow: "hidden",
    }}
  >
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');
      @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.4; } }
      * { box-sizing: border-box; }
      ::-webkit-scrollbar { width: 4px; }
      ::-webkit-scrollbar-track { background: transparent; }
      ::-webkit-scrollbar-thumb { background: ${p.border}; border-radius: 2px; }
      input::placeholder { color: ${p.textDim}; }
    `}</style>

    {sidebarOpen && (
      <div
        onClick={() => setSidebarOpen(false)}
        style={{
          position: "fixed",
          inset: 0,
          backgroundColor: "rgba(0,0,0,0.5)",
          zIndex: 49,
        }}
      />
    )}

    <div
      style={{
        position: "fixed",
        left: 0,
        top: 0,
        bottom: 0,
        width: 280,
        backgroundColor: p.sidebar,
        borderRight: `1px solid ${p.border}`,
        transform: sidebarOpen
          ? "translateX(0)"
          : "translateX(-100%)",
        transition: "transform 0.25s ease",
        zIndex: 50,
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          padding: "20px 16px 16px",
          borderBottom: `1px solid ${p.border}`,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "baseline",
            gap: 8,
          }}
        >
          <span
            style={{
              fontFamily: f.mono,
              fontSize: 18,
              fontWeight: 700,
              color: p.accent,
              letterSpacing: "0.1em",
            }}
          >
            HALO
          </span>
          <span
            style={{
              fontFamily: f.mono,
              fontSize: 9,
              color: p.textDim,
              letterSpacing: "0.05em",
            }}
          >
            v0.1.0
          </span>
        </div>
        <IconBtn onClick={() => setSidebarOpen(false)}>✕</IconBtn>
      </div>

    paddingLeft: 12,
    marginBottom: 8,
  }}
>
  <button
    onClick={() => setOpen(!open)}
    style={{
      background: "none",
      border: "none",
      cursor: "pointer",
      fontFamily: f.sans,
      fontSize: 12,
